{
  "title": "सिस्टम प्रॉम्प्ट की भूमिका",
  "group": "बुनियादी बातें",
  "options": [
    {
      "text": "यह पहले प्रोसेस किया जाता है और उपयोगकर्ता संदेशों की तुलना में अधिक वजन रखता है"
    },
    {
      "text": "यह उपयोगकर्ता संदेश के समान है लेकिन अलग तरीके से दिखाया जाता है"
    },
    {
      "text": "यह केवल API कॉल्स के लिए उपयोग होता है, चैट इंटरफ़ेस के लिए नहीं"
    },
    {
      "text": "यह सत्रों के बीच दीर्घकालिक स्मृति के रूप में बना रहता है"
    }
  ],
  "questionProse": [
    "संदेशों की array में `system` भूमिका और `user` भूमिका के उपयोग का व्यावहारिक प्रभाव क्या है?"
  ],
  "explanationProse": [
    "`system` भूमिका को उच्च प्राथमिकता वाले निर्देशों के रूप में प्रोसेस किया जाता है। मॉडल्स को उपयोगकर्ता संदेशों की तुलना में इसे अधिक वजन देने के लिए प्रशिक्षित किया गया है — यह \"डेवलपर ने क्या कहा\" और \"उपयोगकर्ता ने क्या कहा\" के बीच की वास्तुशिल्पीय सीमा है।",
    "यह जादू नहीं है। यह गारंटी नहीं देता कि मॉडल विरोधी उपयोगकर्ता निर्देशों को नजरअंदाज कर देगा (देखें: प्रॉम्प्ट इंजेक्शन)। लेकिन यह मॉडल की आपके निर्देशों का पालन करने की प्रवृत्ति को सार्थक रूप से बढ़ाता है, विशेषकर उन मॉडलों में जो निर्देश‑अनुपालन में मजबूत हैं।",
    "व्यावहारिक रूप से: अपना पर्सोना, नियम, और व्यवहारिक प्रतिबंध `system` में रखें। प्राप्त किया गया संदर्भ और उपयोगकर्ता डेटा `user` में रखें। कभी भी उपयोगकर्ता‑नियंत्रित इनपुट को `system` में न रखें।"
  ]
}
